bool cmp(const pll &a, const pll &b) {
  bool az = (a.second == 0);
  bool bz = (b.second == 0);

  if (az != bz)
    return !az;

  return a.first < b.first;
}

// -------------------- Solve Function --------------------
/**
 * @brief Main solution function - implement your algorithm here
 * @note This function is called for each test case
 */
bm_always_inline inline void solve() {
  cin >> n >> m;
  a.clear();
  rep(i, 0, n) {
    ll x;
    cin >> x;
    a.insert(x);
  }
  bc.resize(m);
  rep(i, 0, m) { cin >> bc[i].first; }
  rep(i, 0, m) { cin >> bc[i].second; }
  sort(all(bc), cmp);
  DEBUG_LOG(bc);
  ll i{};
  ll ans{};
  for (auto it = a.begin(); it != a.end();) {
    if (i >= m) {
      break;
    }
    auto cur_sword = *it;
    auto &cur_monster = bc[i];
    if (cur_monster.second == 0) {
      break;
    }
    if (cur_sword < cur_monster.first) {
      ++it;
      continue;
    }
    ++ans;
    ++i;
    if (cur_monster.second > 0) {
      auto new_sword = max(cur_sword, cur_monster.second);
      if (new_sword == cur_sword) {
        continue;
      }
      a.insert(new_sword);
      it = a.erase(it);
    } else {
      ++it;
    }
  }
  i = 0;
  for (auto it = a.begin(); it != a.end();) {
    if (i >= m) {
      break;
    }
    auto cur_sword = *it;
    auto &cur_monster = bc[i];
    if (cur_monster.second != 0) {
      i++;
      continue;
    }
    if (cur_sword < cur_monster.first) {
      ++it;
      continue;
    }
    ++ans;
    ++i;
    if (cur_monster.second > 0) {
      auto new_sword = max(cur_sword, cur_monster.second);
      if (new_sword == cur_sword) {
        continue;
      }
      a.insert(new_sword);
      it = a.erase(it);
    } else {
      ++it;
    }
  }
  print(ans);
}

